export default function SpikesSection() {
  const [spikesRef, spikesVisible] = useInView(0.2);
  const [isMobile, setIsMobile] = useState(false);
  const [activeIdx, setActiveIdx] = useState(0);
  // Scroll-hijack state:
  //   "before" → section not yet reached, content flows in normal position
  //   "pinned" → section reached, content fixed to viewport while scroll advances activeIdx
  //   "after"  → all insights shown, content released at wrapper-top + hijackDistance
  //              so it transitions seamlessly from pinned (zero visual jump).
  const [pinState, setPinState] = useState("before");
  const [hijackDist, setHijackDist] = useState(0);
  const storyRef = useRef(null);
  const storyInnerRef = useRef(null);
  // Separate ref for measuring the actual content height. storyInnerRef is the
  // positioning wrapper whose size changes with pinState (fixed + 100vh when
  // pinned), so we can't measure it reliably. This ref points to the real
  // content div which stays the same size throughout.
  const storyContentRef = useRef(null);

  useEffect(() => {
    const checkMobile = () => setIsMobile(window.innerWidth < 768);
    checkMobile();
    window.addEventListener("resize", checkMobile);
    return () => window.removeEventListener("resize", checkMobile);
  }, []);

  /*
   * Scroll-jack the Story section on desktop without touching the section's
   * own layout/spacing.
   *
   * Approach:
   *   - storyRef points to an OUTER wrapper whose natural height = the story
   *     content's natural height (unchanged from original). We dynamically
   *     set a `minHeight` on it equal to (contentHeight + hijackDistance),
   *     so the page has extra scroll room ONLY after the content — never
   *     before or inside it. This preserves the original spacing above and
   *     below the section exactly.
   *   - When the wrapper's top reaches viewport top, we switch to "pinned":
   *     the inner content becomes position: fixed so it stays put while the
   *     user keeps scrolling. scrollDelta within the hijack range drives
   *     activeIdx.
   *   - Once hijackDistance px have been scrolled past the pin point, we
   *     release to "after": content is absolute-positioned at top:hijackDist
   *     within the wrapper. At the transition frame this is visually
   *     identical to the pinned position (zero jump), and from there it
   *     scrolls naturally with the page.
   *
   * On mobile we skip this entirely — no pinning, no extra height, content
   * flows normally and activeIdx stays at 0.
   */
  useEffect(() => {
    if (isMobile) return;

    let hijackDistance = 0;
    let contentHeight = 0;

    const measure = () => {
      const content = storyContentRef.current;
      if (!content) return;
      contentHeight = content.offsetHeight;
      // Give each insight ~40% of viewport height of scroll room before
      // advancing. 6 insights × 0.4vh = 240vh total hijack scroll, which
      // feels snappy without being excessive. Original section without
      // hijack was ~1 viewport, so we add ~240vh of extra scroll room.
      hijackDistance = window.innerHeight * INSIGHTS.length * 0.4;
      setHijackDist(hijackDistance);
      // Set the wrapper's minHeight so extra scroll room exists only past
      // the content's natural bottom — no spacing change above or inside.
      if (storyRef.current) {
        storyRef.current.style.minHeight = `${contentHeight + hijackDistance}px`;
      }
    };

    const onScroll = () => {
      const wrapper = storyRef.current;
      if (!wrapper) return;
      const rect = wrapper.getBoundingClientRect();
      // Pin point: when the top of the wrapper hits the top of the viewport.
      const topOffset = -rect.top;

      if (topOffset <= 0) {
        setPinState("before");
        setActiveIdx(0);
      } else if (topOffset >= hijackDistance) {
        setPinState("after");
        setActiveIdx(INSIGHTS.length - 1);
      } else {
        setPinState("pinned");
        const p = topOffset / hijackDistance;
        const idx = Math.min(INSIGHTS.length - 1, Math.floor(p * INSIGHTS.length));
        setActiveIdx(idx);
      }
    };

    measure();
    onScroll();
    window.addEventListener("scroll", onScroll, { passive: true });
    window.addEventListener("resize", measure, { passive: true });
    return () => {
      window.removeEventListener("scroll", onScroll);
      window.removeEventListener("resize", measure);
      // Clean up inline minHeight on unmount so nothing lingers.
      if (storyRef.current) storyRef.current.style.minHeight = "";
    };
  }, [isMobile]);

  const nextIdx = (activeIdx + 1) % INSIGHTS.length;

  // Positioning for the story inner positioning-wrapper (desktop only).
  //
  // When "pinned": full viewport width, flex row starting at top. We use
  //   alignItems: flex-start + the original 48px top padding so the content's
  //   vertical position matches where it sat just before pinning (the outer
  //   wrapper has the same 48px top padding). This makes the before→pinned
  //   transition visually seamless.
  // When "after": absolute at top:hijackDist — at the pinned→after transition
  //   frame, the wrapper's top is at viewport-top -hijackDist, so an element
  //   at top:hijackDist sits at viewport-top 0. Combined with the same 48px
  //   top padding, the content sits at the exact same position it had in
  //   pinned state at that moment. Zero visual jump.
  // When "before": {} (normal flow, outer's flex centering applies).
  const storyInnerStyle = isMobile
    ? {}
    : pinState === "pinned"
      ? {
          position: "fixed",
          top: 0,
          left: 0,
          right: 0,
          height: "100vh",
          display: "flex",
          alignItems: "flex-start",
          justifyContent: "center",
          padding: "48px 60px",
          boxSizing: "border-box",
          zIndex: 2,
        }
      : pinState === "after"
        ? {
            position: "absolute",
            top: hijackDist,
            left: 0,
            right: 0,
            display: "flex",
            alignItems: "flex-start",
            justifyContent: "center",
            padding: "48px 60px",
            boxSizing: "border-box",
          }
        : {};

  return (
    <>
      {/* ══ 1. SPIKES SECTION ══ */}
      <section style={{
        background: "transparent",
        padding: "10px 5vw 0px",
        display: "flex", flexDirection: "column", alignItems: "center",
        textAlign: "center",
      }}>
        <h2 style={{
          fontFamily: "Inter",
          fontSize: isMobile ? "11.25px" : "22.5px",
          fontWeight: 700, color: "white",
          marginBottom: 48, lineHeight: isMobile ? 1.3 : "150%",
        }}>
          These spikes typically occur due to
        </h2>

        <div ref={spikesRef} style={{
          width: "100%", maxWidth: 1040,
          display: "grid", gridTemplateColumns: "1fr 1fr",
          gap: isMobile ? 12 : 18, marginBottom: 48,
        }}>
          {SPIKES.slice(0, 2).map((item, i) => (
            <SpikeCard key={item.id} item={item} delay={0.1 * i} visible={spikesVisible} isMobile={isMobile} />
          ))}
          <div style={{ gridColumn: "1 / -1" }}>
            <SpikeCard item={SPIKES[2]} delay={0.22} visible={spikesVisible} isMobile={isMobile} />
          </div>
        </div>

        <p style={{
          fontFamily: "Inter",
          fontSize: isMobile ? "8.25px" : "22.5px",
          fontWeight: 300, color: "rgba(255,255,255,1)",
          lineHeight: isMobile ? "16.5px" : "28.5px", maxWidth: 1100,
          opacity: spikesVisible ? 1 : 0,
          transform: spikesVisible ? "translateY(0)" : "translateY(16px)",
          transition: "opacity 0.55s 0.38s, transform 0.55s 0.38s",
          marginBottom: 40,
        }}>
          When hiring volume spikes, verification compromises follow and{" "}
          <strong style={{ color: "#CE1010" }}>risk rates</strong>{" "}
          <br className="sm:flex hidden" />
          inch upward. Even a <strong style={{ color: "white" }}>0.3%</strong>{" "}
          increase at scale translates into{" "}
          <strong style={{ color: "#CE1010" }}>thousands</strong>
          <br className="sm:flex hidden" />
          of additional high-risk profiles entering the ecosystem.
        </p>
      </section>

      {/* ══ 2. STORY SECTION ══ */}
      {/*
       * storyRef → outer wrapper. Its minHeight is dynamically set on desktop
       * to (contentHeight + hijackDistance), so scroll room is added AFTER
       * the content without changing any spacing above/inside it.
       *
       * storyInnerRef → positioning wrapper. Gets storyInnerStyle applied:
       *   before → {} (normal flow, flex-centered by outer)
       *   pinned → fixed to viewport, re-centers its child (the content)
       *   after  → absolute at bottom of outer
       * The content div (with maxWidth: 1100) sits inside this wrapper so
       * its width constraints stay intact regardless of pin state.
       */}
      <div ref={storyRef} style={{
        background: "transparent",
        display: "flex",
        flexDirection: "column",
        alignItems: "center",
        // On mobile keep original center-justify (no hijacking). On desktop
        // we override with flex-start because the dynamic minHeight makes
        // the wrapper much taller than content, and center-justify would
        // float the content to the middle of that tall box. The positioning
        // wrapper (storyInnerRef) handles vertical placement instead.
        justifyContent: isMobile ? "center" : "flex-start",
        padding: isMobile ? "24px 20px" : "48px 60px",
        boxSizing: "border-box",
        position: "relative",
      }}>
        <div ref={storyInnerRef} style={{
          width: "100%",
          display: "flex",
          justifyContent: "center",
          ...storyInnerStyle,
        }}>
        <div ref={storyContentRef} style={{
          width: "100%", maxWidth: 1100,
          display: "flex",
          flexDirection: isMobile ? "column" : "row",
          alignItems: isMobile ? "center" : "stretch",
          // gap: isMobile ? 0 : "4vw",
        }}>

          {/* Left Panel */}
          <div style={{
            width: isMobile ? "100%" : "48%",
            flexShrink: 0,
            display: "flex", flexDirection: "column",
            justifyContent: isMobile ? "flex-start" : "space-between",
            paddingTop: 8, paddingBottom: isMobile ? 20 : 8,
            textAlign: isMobile ? "center" : "left",
          }}>
            <div>
              <h2 style={{
                fontFamily: "Inter", fontWeight: 700, color: "white",
                fontSize: isMobile ? "30px" : "75px",
                lineHeight: isMobile ? 1.1 : 1.0,
                margin: isMobile ? "0 0 16px" : "0 0 24px",
                letterSpacing: isMobile ? "-0.5px" : "-2px",
              }}>
                {isMobile ? (
                  <>The Story Behind<br />the Data</>
                ) : (
                  <>The Story<br />Behind<br />the Data</>
                )}
              </h2>

              <p style={{
                fontFamily: "Inter",
                fontSize: isMobile ? "11px" : "19.5px",
                color: "rgba(255,255,255,0.9)",
                lineHeight: isMobile ? 1.55 : "115%",
                margin: isMobile ? "0 auto 20px" : "0 0 32px",
                maxWidth: isMobile ? "80%" : 340,
                fontWeight: 300,
              }}>
                After analyzing all the numbers, we identified a few observations
                across the segments of truck drivers, delivery partners, and dark
                store employees.
              </p>  
            </div>


          </div>

                    {/* Right Panel */}
          <div style={{
            flex: 1, display: "flex", flexDirection: "column",
            justifyContent: "center",
            minHeight: isMobile ? 220 : 180, width: isMobile ? "100%" : "auto",
            position: "relative",
            paddingRight: isMobile ? 0 : 40,
            paddingLeft: 0,
            textAlign: "left",
          }}>
            {/* Desktop-only progress bar — anchored to outer panel, full height */}
            {!isMobile && (
              <div style={{
                position: "absolute", top: 0, right: 0,
                width: 2, height: "100%",
                background: "rgba(255,255,255,0.12)", borderRadius: 2, overflow: "hidden",
              }}>
                <div style={{
                  width: "100%",
                  height: `${((activeIdx + 1) / INSIGHTS.length) * 100}%`,
                  background: "#CE1010", borderRadius: 2,
                  transition: "height 0.3s ease",
                }} />
              </div>
            )}

            {/* Inner wrapper: narrower, centered on the page,
                so block sits center but text inside is left-aligned */}
            <div style={{
              position: "relative",
              width: isMobile ? 260 : "auto",
              margin: isMobile ? "0 auto" : 0,
              paddingRight: isMobile ? 16 : 0,
            }}>
              {/* Mobile-only progress bar — anchored to inner wrapper, content height */}
              {isMobile && (
                <div style={{
                  position: "absolute", top: 0, right: -15,
                  width: 2, height: "100%",
                  background: "rgba(255,255,255,0.12)", borderRadius: 2, overflow: "hidden",
                }}>
                  <div style={{
                    width: "100%",
                    height: `${((activeIdx + 1) / INSIGHTS.length) * 100}%`,
                    background: "#CE1010", borderRadius: 2,
                    transition: "height 0.3s ease",
                  }} />
                </div>
              )}

              <div key={activeIdx} style={{ animation: "fadeSlideIn 0.45s ease forwards" }}>
                {/* Active insight */}
                <div style={{ marginBottom: isMobile ? 20 : 32 }}>
                  <h3 style={{
                    fontFamily: "Inter",
                    fontSize: isMobile ? "13px" : "19.5px",
                    fontWeight: 700, color: "white",
                    margin: isMobile ? "0 0 8px" : "0 0 12px",
                    lineHeight: 1.4,
                  }}>
                    {INSIGHTS[activeIdx].title}
                  </h3>
                  <p style={{
                    fontFamily: "Inter",
                    fontSize: isMobile ? "10.5px" : "19.5px",
                    color: "rgba(255,255,255,0.9)",
                    margin: 0,
                    fontWeight: 300,
                    lineHeight: isMobile ? 1.55 : "115%",
                  }}>
                    {INSIGHTS[activeIdx].body}
                  </p>
                </div>

                {/* Next insight preview */}
                <div>
                  <h3 style={{
                    fontFamily: "Inter",
                    fontSize: isMobile ? "11.5px" : "19.5px",
                    fontWeight: 600, color: "#f4f4f4",
                    opacity: 0.55,
                    margin: 0,
                    lineHeight: 1.4,
                  }}>
                    {INSIGHTS[nextIdx].title}
                  </h3>
                </div>
              </div>
            </div>
          </div>
      </div>
      </div>
      </div>

      <style>{`
        @keyframes fadeSlideIn {
          from { opacity: 0; transform: translateY(14px); }
          to   { opacity: 1; transform: translateY(0); }
        }
      `}</style>
    </>
  );
}
